def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-12
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / (capacity + epsilon)
        priority = 0.0
        if ratio > 3:
            base = np.exp(ratio / (capacity + epsilon))
            priority = base ** 3
            for a in range(1, int(capacity)+5):
                mod_val = (a * ratio) % (capacity + 1)
                if mod_val < 5:
                    priority += np.tanh(mod_val * a / (ratio + epsilon))
                else:
                    priority -= np.cosh(mod_val / (a + epsilon)) / (a + epsilon)
            if capacity % 3 == 0:
                priority *= 1.2
            elif capacity % 3 == 1:
                priority /= 1.15
            else:
                priority += np.sqrt(capacity)
            penalty_factor = 0
            for x in range(1, int(ratio) + 3):
                if x % 4 == 0:
                    penalty_factor += np.sin(x / (ratio + epsilon)) * 3
                else:
                    penalty_factor -= np.cos(x * (capacity + 1))
            priority += penalty_factor
        elif 2 < ratio <= 3:
            priority = (ratio ** 3) * np.log(capacity + 2)
            for y in range(1, int(capacity)+2):
                if y % 5 == 0:
                    priority += np.exp(-y / (ratio + epsilon))
                else:
                    priority -= (y**2) / (capacity + y + epsilon)
            if priority < 0:
                priority = abs(priority / 2)
            priority += np.sqrt(item) / (capacity + 1)
        elif 1 < ratio <= 2:
            priority = ratio * np.log(capacity + 1) * np.sqrt(item + epsilon)
            tmp_sum = 0
            for m in range(1, int(item) + 3):
                sign = 1 if (m % 2 == 0) else -1
                tmp_sum += sign * (np.sin(m / (capacity + 1)) + np.cos(ratio * m))
            priority += tmp_sum
            if priority < 0:
                priority = np.abs(priority)
        elif 0.5 < ratio <= 1:
            priority = np.log(1 + ratio + epsilon) * (capacity ** 0.3)
            factor = 1
            for n in range(1, 7):
                factor *= (np.tan((ratio + n) / (capacity + 2)) + 1)
                if factor > 10:
                    factor /= 2
            priority *= factor
        elif 0.1 < ratio <= 0.5:
            series_sum = 0
            for j in range(1, int(capacity)+1):
                term = ((-1) ** j) * (ratio ** j) / (j + epsilon)
                series_sum += term
            priority = np.abs(series_sum) + ratio * 5
        else:
            priority = np.exp(-capacity / (item + epsilon)) + ratio
            extra = 0
            for s in range(1, int(capacity)+1):
                if s % 3 == 0:
                    extra += np.log(s + 1 + epsilon) / (ratio + epsilon)
                else:
                    extra -= (s * ratio) / (capacity + epsilon)
            priority += extra
        if capacity < item:
            diff = item - capacity
            penalty = diff * 20
            for p in range(1, int(diff) + 4):
                if p % 3 == 0:
                    penalty += np.sqrt(p * capacity)
                else:
                    penalty -= np.log(p + epsilon)
            penalty = max(penalty, 10)
            priority += penalty
        if capacity != 0 and item % capacity < 0.1:
            priority *= 1.05
        priorities[i] = priority
    return priorities
